// Auto-generated from docs.md — do not edit
export const docsContentHtml = "<h1 id=\"overview\">storage.now API</h1>\n<p>File storage for humans and AI agents. Upload, organize, and share files via a simple REST API.</p>\n<p>Base URL: <code>https://storage.liteio.dev</code></p>\n<table class=\"ref-table\">\n<thead><tr><th>Feature</th><th>Detail</th></tr></thead>\n<tbody>\n<tr><td>Max file size</td><td>100 MB (single PUT), unlimited via presigned URLs</td></tr>\n<tr><td>Auth</td><td>Ed25519 challenge-response or magic link</td></tr>\n<tr><td>Storage</td><td>S3-compatible object storage (R2)</td></tr>\n<tr><td>Metadata</td><td>SQLite at edge (D1)</td></tr>\n<tr><td>Soft delete</td><td>Files go to trash first, permanent delete on empty</td></tr>\n</tbody></table>\n<h1 id=\"auth\">Authentication</h1>\n<p>All API routes (except registration, auth, and public pages) require a Bearer token or session cookie.</p>\n<h2 id=\"register\">Register an Actor</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /actors\nContent-Type: application/json\n\n{\n  &quot;actor&quot;: &quot;a/my-agent&quot;,\n  &quot;public_key&quot;: &quot;&lt;base64url-ed25519-public-key&gt;&quot;,\n  &quot;type&quot;: &quot;agent&quot;\n}\n\n// Response\n{\n  &quot;actor&quot;: &quot;a/my-agent&quot;,\n  &quot;created&quot;: true\n}</code></pre>\n<p>Humans use <code>u/name</code>, agents use <code>a/name</code>. Agents must provide an Ed25519 public key.</p>\n<h2 id=\"challenge\">Challenge-Response Auth</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>// Step 1: Get a challenge nonce\nPOST /auth/challenge\n{&quot;actor&quot;: &quot;a/my-agent&quot;}\n\n// Response\n{\n  &quot;challenge_id&quot;: &quot;ch_...&quot;,\n  &quot;nonce&quot;: &quot;abc123...&quot;,\n  &quot;expires_at&quot;: &quot;2026-03-18T...&quot;\n}\n\n// Step 2: Sign the nonce with your Ed25519 private key, then verify\nPOST /auth/verify\n{\n  &quot;challenge_id&quot;: &quot;ch_...&quot;,\n  &quot;actor&quot;: &quot;a/my-agent&quot;,\n  &quot;signature&quot;: &quot;&lt;base64url-signature-of-nonce&gt;&quot;\n}\n\n// Response\n{\n  &quot;access_token&quot;: &quot;...&quot;,\n  &quot;expires_at&quot;: &quot;2026-03-18T...&quot;\n}\n\n// Step 3: Use the token\nAuthorization: Bearer &lt;access_token&gt;</code></pre>\n<h2 id=\"magic-link\">Magic Link Auth (Humans)</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /auth/magic-link\n{&quot;email&quot;: &quot;alice@example.com&quot;}\n\n// Response\n{&quot;ok&quot;: true, &quot;magic_link&quot;: &quot;https://storage.liteio.dev/auth/magic/...&quot;}</code></pre>\n<p>Opens a session in the browser. No password needed.</p>\n<h2 id=\"logout\">Logout</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /auth/logout\nGET /auth/logout</code></pre>\n<p>Ends the current session. Accepts both POST and GET (for link-based logout).</p>\n<h1 id=\"files\">Files</h1>\n<p>Upload, download, and delete files using their path.</p>\n<h2 id=\"upload\">Upload a File</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>PUT /files/docs/readme.md\nAuthorization: Bearer &lt;token&gt;\nContent-Type: text/markdown\n\n&lt;file bytes&gt;\n\n// Response (201 Created or 200 Updated)\n{\n  &quot;id&quot;: &quot;o_...&quot;,\n  &quot;path&quot;: &quot;docs/readme.md&quot;,\n  &quot;name&quot;: &quot;readme.md&quot;,\n  &quot;content_type&quot;: &quot;text/markdown&quot;,\n  &quot;size&quot;: 1234,\n  &quot;created_at&quot;: 1710700000000\n}</code></pre>\n<p>Parent folders are auto-created. Content-Type is auto-detected from extension if not provided. Max 100 MB.</p>\n<h2 id=\"download\">Download a File</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /files/docs/readme.md\nAuthorization: Bearer &lt;token&gt;\n\n// Response: file bytes\n// Headers: Content-Type, Content-Length, ETag, Last-Modified, Content-Disposition</code></pre>\n<p>Trashed files are not downloadable. Sets <code>accessed_at</code> on the file.</p>\n<h2 id=\"delete-file\">Delete a File</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>DELETE /files/docs/readme.md\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{&quot;deleted&quot;: true}</code></pre>\n<p>Permanently deletes the file and its R2 object. To soft-delete, use <code>POST /drive/trash</code> instead.</p>\n<h2 id=\"head-file\">File Metadata (HEAD)</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>HEAD /files/docs/readme.md\nAuthorization: Bearer &lt;token&gt;\n\n// Response headers: Content-Type, Content-Length, Last-Modified</code></pre>\n<h1 id=\"folders\">Folders</h1>\n<p>Folders are virtual metadata entries. Created automatically when uploading files, or explicitly.</p>\n<h2 id=\"create-folder\">Create a Folder</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /folders\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;docs/reports&quot;}\n\n// Response (201)\n{\n  &quot;id&quot;: &quot;o_...&quot;,\n  &quot;path&quot;: &quot;docs/reports/&quot;,\n  &quot;name&quot;: &quot;reports&quot;,\n  &quot;created&quot;: true\n}</code></pre>\n<p>Parent folders are auto-created. Returns <code>created: false</code> if already exists.</p>\n<h2 id=\"list-folder\">List Folder Contents</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>// List root\nGET /folders\nAuthorization: Bearer &lt;token&gt;\n\n// List subfolder\nGET /folders/docs\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;path&quot;: &quot;docs/&quot;,\n  &quot;items&quot;: [\n    {&quot;name&quot;: &quot;reports&quot;, &quot;path&quot;: &quot;docs/reports/&quot;, &quot;is_folder&quot;: true, &quot;starred&quot;: false, ...},\n    {&quot;name&quot;: &quot;readme.md&quot;, &quot;path&quot;: &quot;docs/readme.md&quot;, &quot;is_folder&quot;: false, &quot;size&quot;: 1234, &quot;starred&quot;: false, ...}\n  ]\n}</code></pre>\n<p>Items are sorted: folders first, then files alphabetically. Trashed items are excluded.</p>\n<h2 id=\"delete-folder\">Delete a Folder</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>DELETE /folders/docs/reports\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{&quot;deleted&quot;: true}</code></pre>\n<p>Folder must be empty. Delete or move files inside first.</p>\n<h1 id=\"shares\">Shares</h1>\n<p>Share files with other actors. Grant read or write access.</p>\n<h2 id=\"create-share\">Create a Share</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /shares\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{\n  &quot;path&quot;: &quot;docs/readme.md&quot;,\n  &quot;grantee&quot;: &quot;u/bob&quot;,\n  &quot;permission&quot;: &quot;read&quot;\n}\n\n// Response (201)\n{\n  &quot;id&quot;: &quot;sh_...&quot;,\n  &quot;path&quot;: &quot;docs/readme.md&quot;,\n  &quot;grantee&quot;: &quot;u/bob&quot;,\n  &quot;permission&quot;: &quot;read&quot;,\n  &quot;created_at&quot;: 1710700000000\n}</code></pre>\n<h2 id=\"list-shares\">List Shares</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /shares\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;given&quot;: [...],    // shares you created\n  &quot;received&quot;: [...]  // shares granted to you\n}</code></pre>\n<h2 id=\"revoke-share\">Revoke a Share</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>DELETE /shares/sh_abc123\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{&quot;deleted&quot;: true}</code></pre>\n<h2 id=\"shared-files\">Shared Files</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>// List files shared with you\nGET /shared\nAuthorization: Bearer &lt;token&gt;\n\n// Download a shared file\nGET /shared/u%2Falice/docs/readme.md\nAuthorization: Bearer &lt;token&gt;</code></pre>\n<h1 id=\"presign\">Presigned URLs</h1>\n<p>For large files or high-throughput scenarios, use presigned URLs to upload/download directly to object storage — bypassing the worker entirely. No file bytes pass through the API server.</p>\n<p><strong>Flow:</strong> Request a signed URL → PUT/GET directly to storage → Confirm upload (for writes).</p>\n<h2 id=\"presign-upload\">Get Upload URL</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /presign/upload\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{\n  &quot;path&quot;: &quot;models/v3.bin&quot;,\n  &quot;content_type&quot;: &quot;application/octet-stream&quot;,\n  &quot;expires&quot;: 3600\n}\n\n// Response\n{\n  &quot;upload_url&quot;: &quot;https://...signed-url...&quot;,\n  &quot;path&quot;: &quot;models/v3.bin&quot;,\n  &quot;content_type&quot;: &quot;application/octet-stream&quot;,\n  &quot;expires_in&quot;: 3600,\n  &quot;method&quot;: &quot;PUT&quot;,\n  &quot;headers&quot;: {&quot;Content-Type&quot;: &quot;application/octet-stream&quot;}\n}</code></pre>\n<p>The signed URL is valid for <code>expires</code> seconds (default 1 hour, max 24 hours). After uploading, call <code>/presign/complete</code> to sync metadata.</p>\n<h2 id=\"presign-download\">Get Download URL</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /presign/download\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;models/v3.bin&quot;, &quot;expires&quot;: 3600}\n\n// Response\n{\n  &quot;download_url&quot;: &quot;https://...signed-url...&quot;,\n  &quot;path&quot;: &quot;models/v3.bin&quot;,\n  &quot;name&quot;: &quot;v3.bin&quot;,\n  &quot;content_type&quot;: &quot;application/octet-stream&quot;,\n  &quot;size&quot;: 47185920,\n  &quot;expires_in&quot;: 3600\n}</code></pre>\n<p>No confirmation needed for downloads. The file must exist (verified against metadata before signing).</p>\n<h2 id=\"presign-complete\">Confirm Upload</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /presign/complete\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;models/v3.bin&quot;}\n\n// Response\n{\n  &quot;id&quot;: &quot;o_...&quot;,\n  &quot;path&quot;: &quot;models/v3.bin&quot;,\n  &quot;name&quot;: &quot;v3.bin&quot;,\n  &quot;content_type&quot;: &quot;application/octet-stream&quot;,\n  &quot;size&quot;: 47185920,\n  &quot;created_at&quot;: 1710700000000\n}</code></pre>\n<p>Call after a presigned upload succeeds. Verifies the file exists in storage, reads its actual size/type, and creates or updates the metadata record. Parent folders are auto-created.</p>\n<h1 id=\"drive\">Drive</h1>\n<p>Drive endpoints provide Google Drive-class file management features: star, rename, move, copy, trash, restore, search, and more. All require authentication.</p>\n<h2 id=\"star\">Star / Unstar</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>PATCH /drive/star\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;docs/readme.md&quot;, &quot;starred&quot;: 1}\n\n// Response\n{&quot;path&quot;: &quot;docs/readme.md&quot;, &quot;starred&quot;: 1}</code></pre>\n<p>Set <code>starred</code> to <code>1</code> to star, <code>0</code> to unstar.</p>\n<h2 id=\"rename\">Rename</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /drive/rename\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;docs/old-name.md&quot;, &quot;new_name&quot;: &quot;new-name.md&quot;}\n\n// Response\n{\n  &quot;old_path&quot;: &quot;docs/old-name.md&quot;,\n  &quot;new_path&quot;: &quot;docs/new-name.md&quot;,\n  &quot;name&quot;: &quot;new-name.md&quot;\n}</code></pre>\n<p>Renaming a folder cascades the path change to all children. R2 objects are copied to the new key and the old key is deleted.</p>\n<h2 id=\"move\">Move</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /drive/move\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;paths&quot;: [&quot;docs/readme.md&quot;, &quot;images/logo.svg&quot;], &quot;destination&quot;: &quot;archive/&quot;}\n\n// Response\n{&quot;moved&quot;: 2}</code></pre>\n<p>Moves files and folders to a new parent directory. Destination must end with <code>/</code> or be empty string for root. Folder moves cascade to all children.</p>\n<h2 id=\"copy\">Copy</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /drive/copy\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;docs/readme.md&quot;}\n\n// Response\n{\n  &quot;id&quot;: &quot;o_...&quot;,\n  &quot;path&quot;: &quot;docs/readme (copy).md&quot;,\n  &quot;name&quot;: &quot;readme (copy).md&quot;\n}</code></pre>\n<p>Creates a duplicate file. Appends <code>(copy)</code> to the name, incrementing if needed. Folder copy is not supported.</p>\n<h2 id=\"trash\">Trash</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /drive/trash\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;paths&quot;: [&quot;docs/readme.md&quot;, &quot;images/&quot;]}\n\n// Response\n{&quot;trashed&quot;: 2}</code></pre>\n<p>Soft-deletes items by setting <code>trashed_at</code>. Folder trash cascades to all children. Trashed items are excluded from folder listings and search.</p>\n<h2 id=\"restore\">Restore</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>POST /drive/restore\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;paths&quot;: [&quot;docs/readme.md&quot;, &quot;images/&quot;]}\n\n// Response\n{&quot;restored&quot;: 2}</code></pre>\n<p>Restores items from trash by clearing <code>trashed_at</code>. Folder restore cascades to all children.</p>\n<h2 id=\"empty-trash\">Empty Trash</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>DELETE /drive/trash\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{&quot;deleted&quot;: 5}</code></pre>\n<p>Permanently deletes all trashed items. Removes R2 objects and D1 metadata. Shares on deleted objects are also removed. This action is irreversible.</p>\n<h2 id=\"list-trash\">List Trash</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /drive/trash\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;items&quot;: [\n    {&quot;id&quot;: &quot;o_...&quot;, &quot;name&quot;: &quot;readme.md&quot;, &quot;path&quot;: &quot;docs/readme.md&quot;, &quot;trashed_at&quot;: 1710700000000, ...}\n  ]\n}</code></pre>\n<h2 id=\"recent\">Recent Files</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /drive/recent\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;items&quot;: [...]\n}</code></pre>\n<p>Returns the 50 most recently accessed files (by <code>accessed_at</code>), excluding folders and trashed items.</p>\n<h2 id=\"starred\">Starred Items</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /drive/starred\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;items&quot;: [...]\n}</code></pre>\n<p>Returns all starred, non-trashed items (files and folders).</p>\n<h2 id=\"search\">Search</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /drive/search?q=readme&amp;type=text&amp;starred=1\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;query&quot;: &quot;readme&quot;,\n  &quot;items&quot;: [...]\n}</code></pre>\n<p>Search files by name. Optional filters:</p>\n<table class=\"ref-table\">\n<thead><tr><th>Param</th><th>Description</th></tr></thead>\n<tbody>\n<tr><td>q</td><td>Search term (matched against name with LIKE)</td></tr>\n<tr><td>type</td><td>Filter by content_type prefix (e.g. <code>image</code>, <code>text</code>, <code>application/pdf</code>)</td></tr>\n<tr><td>starred</td><td>Set to <code>1</code> to only return starred items</td></tr>\n</tbody></table>\n<h2 id=\"stats\">Drive Stats</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>GET /drive/stats\nAuthorization: Bearer &lt;token&gt;\n\n// Response\n{\n  &quot;file_count&quot;: 24,\n  &quot;folder_count&quot;: 14,\n  &quot;total_size&quot;: 163405923,\n  &quot;trash_count&quot;: 2,\n  &quot;quota&quot;: 5368709120\n}</code></pre>\n<p>Returns storage usage summary. Quota is 5 GB.</p>\n<h2 id=\"description\">Update Description</h2>\n<pre><button class=\"cb\" onclick=\"cp(this)\">Copy</button><code>PATCH /drive/description\nAuthorization: Bearer &lt;token&gt;\nContent-Type: application/json\n\n{&quot;path&quot;: &quot;docs/readme.md&quot;, &quot;description&quot;: &quot;Project overview&quot;}\n\n// Response\n{&quot;path&quot;: &quot;docs/readme.md&quot;, &quot;description&quot;: &quot;Project overview&quot;}</code></pre>\n<h1 id=\"endpoints\">All Endpoints</h1>\n<table class=\"ref-table\">\n<thead><tr><th>Method</th><th>Path</th><th>Description</th><th>Auth</th></tr></thead>\n<tbody>\n<tr><td>POST</td><td>/actors</td><td>Register actor</td><td>No</td></tr>\n<tr><td>POST</td><td>/auth/challenge</td><td>Get challenge nonce</td><td>No</td></tr>\n<tr><td>POST</td><td>/auth/verify</td><td>Verify signature, get token</td><td>No</td></tr>\n<tr><td>POST</td><td>/auth/magic-link</td><td>Request magic link</td><td>No</td></tr>\n<tr><td>GET</td><td>/auth/magic/:token</td><td>Verify magic link</td><td>No</td></tr>\n<tr><td>POST</td><td>/auth/logout</td><td>End session</td><td>No</td></tr>\n<tr><td>GET</td><td>/auth/logout</td><td>End session (link)</td><td>No</td></tr>\n<tr><td>PUT</td><td>/files/*path</td><td>Upload file</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/files/*path</td><td>Download file</td><td>Yes</td></tr>\n<tr><td>DELETE</td><td>/files/*path</td><td>Delete file</td><td>Yes</td></tr>\n<tr><td>HEAD</td><td>/files/*path</td><td>File metadata</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/presign/upload</td><td>Get presigned upload URL</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/presign/download</td><td>Get presigned download URL</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/presign/complete</td><td>Confirm presigned upload</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/folders</td><td>Create folder</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/folders</td><td>List root</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/folders/*path</td><td>List folder contents</td><td>Yes</td></tr>\n<tr><td>DELETE</td><td>/folders/*path</td><td>Delete empty folder</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/shares</td><td>Create share</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/shares</td><td>List shares</td><td>Yes</td></tr>\n<tr><td>DELETE</td><td>/shares/:id</td><td>Revoke share</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/shared</td><td>Files shared with me</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/shared/:owner/*path</td><td>Download shared file</td><td>Yes</td></tr>\n<tr><td>PATCH</td><td>/drive/star</td><td>Star or unstar item</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/drive/rename</td><td>Rename file or folder</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/drive/move</td><td>Move items to new folder</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/drive/copy</td><td>Duplicate a file</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/drive/trash</td><td>Trash items (soft delete)</td><td>Yes</td></tr>\n<tr><td>POST</td><td>/drive/restore</td><td>Restore items from trash</td><td>Yes</td></tr>\n<tr><td>DELETE</td><td>/drive/trash</td><td>Empty trash (permanent)</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/drive/trash</td><td>List trashed items</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/drive/recent</td><td>Recently accessed files</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/drive/starred</td><td>Starred items</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/drive/search</td><td>Search files by name</td><td>Yes</td></tr>\n<tr><td>GET</td><td>/drive/stats</td><td>Storage usage stats</td><td>Yes</td></tr>\n<tr><td>PATCH</td><td>/drive/description</td><td>Update file description</td><td>Yes</td></tr>\n</tbody></table>\n";
